mapper.select:
/* selectOpinionList */ SELECT pbl_data_opnn_oid, pbl_data_opnn_ttl, pbl_data_opnn_cn , reg_id, reg_dt, mdfcn_id, mdfcn_dt FROM ${schema}.pbl_data_opnn
AND pbl_data_opnn_oid = #{pblDataOpnnOid}
AND pbl_data_opnn_ttl LIKE CONCAT('%',#{keyword},'%')
AND reg_dt >= #{regDtFrom}
AND reg_dt < DATE_ADD(#{regDtTo}, INTERVAL 1 DAY)
ORDER BY pbl_data_opnn_oid DESC
